class Solution {
    public boolean isSubstringPresent(String s) {
        int n = s.length();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (s.substring(i, j + 1).equals(s.substring(n - j, n - i))) {
                    return true;
                }
            }
        }
        return false;
    }
}
```

